// Calculate total hours per client
const records = $input.all();
const timeByClient = {};

for (const record of records) {
  const fields = record.json.fields || {};
  const client = fields.Client || 'Unassigned';
  const hours = parseFloat(fields.Hours) || 0;

  if (!timeByClient[client]) {
    timeByClient[client] = { client, totalHours: 0, entries: [] };
  }
  timeByClient[client].totalHours += hours;
  timeByClient[client].entries.push({
    description: fields.Description || '',
    hours: hours,
    date: fields.Date || ''
  });
}

const summary = Object.values(timeByClient).map(c => ({
  client: c.client,
  totalHours: Math.round(c.totalHours * 100) / 100,
  rate: 50, // USD/hour - adjust per client
  amount: Math.round(c.totalHours * 50 * 100) / 100,
  entries: c.entries
}));

return summary.map(c => ({ json: c }));

