// Generate invoice text
const summary = $input.first().json;
const date = new Date().toISOString().split('T')[0];

let text = `INVOICE - ${date}
`;
text += `Freelancer: Wang Zhe
`;
text += `Client: ${summary.client}

`;
text += `Hours Breakdown:
`;

for (const entry of summary.entries) {
  text += `- ${entry.date}: ${entry.hours}h - ${entry.description}
`;
}

text += `
Total Hours: ${summary.totalHours}h
`;
text += `Rate: $${summary.rate}/hour
`;
text += `Amount Due: $${summary.amount}
`;

return { json: { text, subject: `Invoice ${date} - ${summary.client}`, amount: summary.amount } };
